get.__example:
local c = require "c"

-- Creates a 2 dimensions C array with 3 rows of 4 chars
local CharArray = c.Array("c", 3, 4)

local array = CharArray {
    { "a", "b", "c", '\0' },
    { "d", "e", "f", '\0' },
    { "g", "h", "i", '\0' }
}

print(array:get(0, 0)) -- outputs "a"

set.__example:
local c = require "c"

-- Creates a 2 dimensions C array with 3 rows of 4 chars
local CharArray = c.Array("c", 3, 4)

local array = CharArray {
    { "a", "b", "c", '\0' },
    { "d", "e", "f", '\0' },
    { "g", "h", "i", '\0' }
}

array:set(0, 0, 65)

print(array:set(0, 0)) -- outputs "A"
